template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen::write to insert records
  auto write_op = sqlgen::write(records);
  auto result = write_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the table type based on table_name
  if (table_name == "Student") {
    using TableType = Student;
    using IdType = typename Student::SNo;

    // Create update statement
    auto update_stmt = sqlgen::update<TableType>(
      sqlgen::col<"SNo">.set(record_id),
      sqlgen::col<col_name>.set(new_value)
    ) | sqlgen::where(sqlgen::col<"SNo"> == record_id);

    // Execute update
    auto result = update_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to update record");
    }
  } else if (table_name == "Course") {
    using TableType = Course;
    using IdType = typename Course::CID;

    auto update_stmt = sqlgen::update<TableType>(
      sqlgen::col<"CID">.set(record_id),
      sqlgen::col<col_name>.set(new_value)
    ) | sqlgen::where(sqlgen::col<"CID"> == record_id);

    auto result = update_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to update record");
    }
  } else if (table_name == "Score") {
    using TableType = Score;
    using IdType = typename Score::ScID;

    auto update_stmt = sqlgen::update<TableType>(
      sqlgen::col<"ScID">.set(record_id),
      sqlgen::col<col_name>.set(new_value)
    ) | sqlgen::where(sqlgen::col<"ScID"> == record_id);

    auto result = update_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to update record");
    }
  } else if (table_name == "Major") {
    using TableType = Major;
    using IdType = typename Major::MID;

    auto update_stmt = sqlgen::update<TableType>(
      sqlgen::col<"MID">.set(record_id),
      sqlgen::col<col_name>.set(new_value)
    ) | sqlgen::where(sqlgen::col<"MID"> == record_id);

    auto result = update_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to update record");
    }
  } else {
    throw std::runtime_error("Invalid table name");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

