  if (table_name == "Student") {
    using TableType = Student;
    using IdType = typename Student::SNo;

    auto delete_stmt = sqlgen::delete_from<TableType> |
                      sqlgen::where(sqlgen::col<"SNo"> == record_id);

    auto result = delete_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Course") {
    using TableType = Course;
    using IdType = typename Course::CID;

    auto delete_stmt = sqlgen::delete_from<TableType> |
                      sqlgen::where(sqlgen::col<"CID"> == record_id);

    auto result = delete_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Score") {
    using TableType = Score;
    using IdType = typename Score::ScID;

    auto delete_stmt = sqlgen::delete_from<TableType> |
                      sqlgen::where(sqlgen::col<"ScID"> == record_id);

    auto result = delete_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Major") {
    using TableType = Major;
    using IdType = typename Major::MID;

    auto delete_stmt = sqlgen::delete_from<TableType> |
                      sqlgen::where(sqlgen::col<"MID"> == record_id);

    auto result = delete_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else {
    throw std::runtime_error("Invalid table name");
  }
}
