  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Build the query using sqlgen
    auto query = sqlgen::select_from<Product, "p">(
        "category"_t1,
        sqlgen::sum("quantity"_t2).as<"total_qty">(),
        sqlgen::sum("amount"_t2).as<"total_amt">()
    ) | sqlgen::inner_join<Sale, "s">("product_id"_t1 == "product_id"_t2)
      | sqlgen::group_by("category"_t1)
      | sqlgen::where(sqlgen::sum("amount"_t2) > 5000.0);

    // Execute the query and return results
    auto result = query(conn);

    // Convert the result to CategoryReport objects
    std::vector<CategoryReport> reports;
    for (const auto& row : result) {
        reports.push_back(CategoryReport{
            .category = row.category,
            .total_qty = row.total_qty,
            .total_amt = row.total_amt
        });
    }

    return reports;
}

}  // namespace query_product_sales_report
