        if (!update_result) {
            conn->rollback();
            return false;
        }

        // Commit transaction
        auto commit_result = conn->commit();
        if (!commit_result) {
            return false;
        }

    } catch (...) {
        // Rollback on any exception
        conn->rollback();
        return false;
    }

    return true;
}

}  // namespace soft_delete_records
