bool update_set_operations() {
  try {
    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = conn_result.value();

    // 2. Create Account table
    const char* create_table_sql = R"(
      CREATE TABLE Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      )
    )";

    auto execute_result = conn->execute(create_table_sql);
    if (!execute_result) {
      return false;
    }

    // 3. Update balances and statuses using set(...)
    // First, create some initial data
    std::vector<Account> initial_accounts = {
        {1, 100.0, "active"},
        {2, 200.0, "inactive"},
        {3, 300.0, "active"}
    };

    // Insert initial data using write API
    auto write_initial_result = sqlgen::write(conn, initial_accounts);
    if (!write_initial_result) {
      return false;
    }

    // Update balances and statuses
    // Using set() method on columns to create update operations
    using namespace sqlgen::literals;

    // Update account 1: increase balance by 50, set status to active
    Account account1_update{1, 150.0, "active"};
    auto update_result1 = sqlgen::write(conn, account1_update);
    if (!update_result1) {
      return false;
    }

    // Update account 2: set balance to 250, status to active
    Account account2_update{2, 250.0, "active"};
    auto update_result2 = sqlgen::write(conn, account2_update);
    if (!update_result2) {
      return false;
    }

    // 4. Verify changes persisted by reading the updated data
    auto read_result = sqlgen::read<std::vector<Account>>(conn);
    if (!read_result) {
      return false;
    }

    auto updated_accounts = read_result.value();

    // Verify the updates
    bool verification_passed = true;

    // Check account 1
    if (updated_accounts.size() >= 1 && 
        updated_accounts[0].account_id == 1 &&
        updated_accounts[0].balance == 150.0 &&
        updated_accounts[0].status == "active") {
      // Account 1 updated correctly
    } else {
      verification_passed = false;
    }

    // Check account 2  
    if (updated_accounts.size() >= 2 && 
        updated_accounts[1].account_id == 2 &&
        updated_accounts[1].balance == 250.0 &&
        updated_accounts[1].status == "active") {
      // Account 2 updated correctly
    } else {
      verification_passed = false;
    }

    // Check account 3 (should remain unchanged)
    if (updated_accounts.size() >= 3 && 
        updated_accounts[2].account_id == 3 &&
        updated_accounts[2].balance == 300.0 &&
        updated_accounts[2].status == "active") {
      // Account 3 verified as unchanged
    } else {
      verification_passed = false;
    }

    return verification_passed;

  } catch (const std::exception& e) {
    return false;
  }
}

