#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace select_from_read_to_vector {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  int pages;
};

std::vector<Book> select_from_read_to_vector() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect();

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<Book>(&Book::book_id, &Book::title, &Book::pages)
               | sqlgen::order_by(&Book::pages)  // Order by pages in descending order
               | sqlgen::to<std::vector<Book>>;  // Convert to vector of Book structs

  // Execute the query and return the result
  return query(conn).value();
}

}  // namespace select_from_read_to_vector
```

## Explanation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish a connection to an SQLite database (defaults to in-memory database).

2. **Query Construction**: 
   - `sqlgen::select_from<Book>(&Book::book_id, &Book::title, &Book::pages)` creates a SELECT query for all columns from the Book table
   - `| sqlgen::order_by(&Book::pages)` applies ordering by the pages column in descending order
   - `| sqlgen::to<std::vector<Book>>` specifies that the results should be converted to a vector of Book structs

3. **Query Execution**: The query object is called with the connection `query(conn)` to execute it against the database.

4. **Result Handling**: `.value()` extracts the successful result from the returned `Result` type, throwing an exception if there was an error.

This implementation follows the sqlgen library's fluent interface pattern using the pipe operator (`|`) to chain operations, and correctly handles the conversion from query results to the desired vector of Book structs.

