  write(conn, emps).value();

  // Perform INNER JOIN
  auto inner_query = select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2);
  auto inner_range = inner_query(conn);
  std::vector<JoinResult> inner_results;
  for (auto& row : inner_range) {
    inner_results.push_back(row);
  }

  // Perform LEFT JOIN
  auto left_query = select_from<Employee, "e">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | left_join<Department, "d">("department_id"_t2 == "department_id"_t1);
  auto left_range = left_query(conn);
  std::vector<JoinResult> left_results;
  for (auto& row : left_range) {
    left_results.push_back(row);
  }

  // Perform RIGHT JOIN
  auto right_query = select_from<Employee, "e">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | right_join<Department, "d">("department_id"_t2 == "department_id"_t1);
  auto right_range = right_query(conn);
  std::vector<JoinResult> right_results;
  for (auto& row : right_range) {
    right_results.push_back(row);
  }

  // Perform FULL JOIN
  auto full_query = select_from<Department, "d">("department_name"_t1, "first_name"_t2, "last_name"_t2, "salary"_t2)
                    | full_join<Employee, "e">("department_id"_t1 == "department_id"_t2);
  auto full_range = full_query(conn);
  std::vector<JoinResult> full_results;
  for (auto& row : full_range) {
    full_results.push_back(row);
  }

  // Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = inner_results,
      .left_join_results = left_results,
      .right_join_results = right_results,
      .full_join_results = full_results
  };
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Creation & Data Insertion**: Uses `sqlgen::write()` to automatically create tables and insert the provided department and employee data
3. **Join Operations**:
   - **INNER JOIN**: Matches employees with their departments
   - **LEFT JOIN**: Includes all employees even if they don't have departments
   - **RIGHT JOIN**: Includes all departments even if they don't have employees
   - **FULL JOIN**: Combines all employees and departments, showing NULLs where no matches exist
4. **Result Collection**: Each join result is collected into a `std::vector<JoinResult>` where fields are `std::optional` to handle NULL values from outer joins
5. **Return Value**: Returns a `JoinAnalysis` struct containing all four join results

The implementation follows the sqlgen library patterns demonstrated in the reference materials, using the fluent interface for building queries and proper error handling with `.value()` for Result types.

