#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<Post>(
                 "user_id"_c,
                 "name"_c,
                 sqlgen::count().as<"post_count">(),
                 sqlgen::avg(sqlgen::length("content"_c)).as<"avg_length">())
             | sqlgen::inner_join<User>("user_id"_c == "user_id"_c)
             | sqlgen::group_by("user_id"_c)
             | sqlgen::to<std::vector<Stats>>;

  // Execute the query and return the result
  return query(conn).value();
}

}  // namespace group_by_with_aggregations
```

## Explanation of the Implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Query Construction**: Uses `sqlgen::select_from<Post>` to start building the query from the Post table.

3. **Column Selection**: Selects the required columns:
   - `"user_id"_c` - user ID from the Post table
   - `"name"_c` - name from the User table (via join)
   - `sqlgen::count().as<"post_count">()` - COUNT aggregation with alias
   - `sqlgen::avg(sqlgen::length("content"_c)).as<"avg_length">()` - AVG of content length with alias

4. **Table Join**: Uses `sqlgen::inner_join<User>("user_id"_c == "user_id"_c)` to join the User table on the user_id column.

5. **Grouping**: Uses `sqlgen::group_by("user_id"_c)` to group results by user ID.

6. **Return Type Specification**: Uses `sqlgen::to<std::vector<Stats>>` to specify the return type.

7. **Query Execution**: Calls the query with the connection and returns the result using `.value()` to extract the vector from the Result type.

This implementation follows sqlgen's fluent interface pattern and correctly handles the aggregation requirements while maintaining proper type safety through the use of the `Stats` struct.

